     2→//! module_12 – Hyperparameter Tuning & Experiment Tracking
     3→//!
     4→//! This module lives in the “Model Ops” layer of VisuTility Orchestrator.
     5→//! It provides two core capabilities:
     6→//!  1. Strategy-based hyper-parameter tuning (currently Random Search,
     7→//!     but additional strategies can be plugged in at runtime).
     8→//!  2. Thread-safe, observer-friendly experiment tracking that can be
     9→//!     queried by other layers (e.g. Model Registry, Monitoring).
    10→//!
    11→//! Design patterns in play
    12→//! -----------------------
    13→//! • Strategy Pattern  – `HyperParamTuner` (trait) + concrete impls.  
    14→//! • Observer Pattern  – `TrainingEvent` + `TrainingObserver` for model
    15→//!                       monitoring / automated retraining triggers.
    16→//! • Factory Pattern   – The `TunerFactory` decides which strategy to
    17→//!                       instantiate based on runtime config.
    18→//!
    19→//! NOTE: This file does not touch any hardware-accelerated CV code;
    20→//! it focuses purely on orchestration concerns.
    21→
    22→// External crates -----------------------------------------------------------
    23→use rand::{distributions::Uniform, prelude::*};
    24→use serde::{Deserialize, Serialize};
    25→use std::{
    26→    collections::HashMap,
    27→    fmt,
    28→    sync::Arc,
    29→    time::{Duration, SystemTime},
    30→};
    31→use thiserror::Error;
    32→use tokio::sync::{broadcast, RwLock};
    33→use uuid::Uuid;
    34→
    35→// Internal exports ----------------------------------------------------------
    36→pub use error::TunerError;
    37→pub use observer::{TrainingEvent, TrainingObserver};
    38→pub use tracker::{ExperimentRun, ExperimentTracker};
    39→pub use tuner::{HyperParamSpec, HyperParamTuner, RandomSearchTuner, TunerFactory};
    40→
    41→// ---------------------------------------------------------------------------
    42→mod error {
    43→    use super::*;
    44→
    45→    /// Domain-specific errors for hyper-parameter tuning & tracking.
    46→    #[derive(Debug, Error)]
    47→    pub enum TunerError {
    48→        #[error("Unknown tuner strategy: {0}")]
    49→        UnknownStrategy(String),
    50→        #[error("Experiment run not found: {0}")]
    51→        UnknownRun(Uuid),
    52→        #[error("Metric key already exists in this step: {0}")]
    53→        DuplicateMetricKey(String),
    54→        #[error("Serialization error: {0}")]
    55→        SerdeError(#[from] serde_json::Error),
    56→        #[error("Internal error: {0}")]
    57→        Internal(String),
    58→    }
    59→}
    60→
    61→// ---------------------------------------------------------------------------
    62→mod observer {
    63→    use super::*;
    64→
    65→    /// Observable events emitted by the training loop.
    66→    #[derive(Debug, Clone)]
    67→    pub enum TrainingEvent {
    68→        EpochEnd {
    69→            run_id: Uuid,
    70→            epoch: usize,
    71→            metrics: HashMap<String, f64>,
    72→            timestamp: SystemTime,
    73→        },
    74→        TrainingEnd {
    75→            run_id: Uuid,
    76→            final_metrics: HashMap<String, f64>,
    77→            duration: Duration,
    78→            timestamp: SystemTime,
    79→        },
    80→    }
    81→
    82→    /// Observer trait that other layers can implement to react to events.
    83→    pub trait TrainingObserver: Send + Sync {
    84→        fn on_event(&self, event: &TrainingEvent);
    85→    }
    86→}
    87→
    88→// ---------------------------------------------------------------------------
    89→mod tracker {
    90→    use super::*;
    91→
    92→    /// Metadata for one experiment run.
    93→    #[derive(Debug, Clone, Serialize, Deserialize)]
    94→    pub struct ExperimentRun {
    95→        pub run_id: Uuid,
    96→        pub params: HashMap<String, HyperParamValue>,
    97→        pub start_time: SystemTime,
    98→        pub end_time: Option<SystemTime>,
    99→        pub metrics: HashMap<String, f64>,
   100→        pub tags: Vec<String>,
   101→    }
   102→
   103→    /// Thread-safe experiment tracker that broadcasts events to observers.
   104→    #[derive(Clone)]
   105→    pub struct ExperimentTracker {
   106→        state: Arc<RwLock<HashMap<Uuid, ExperimentRun>>>,
   107→        broadcaster: broadcast::Sender<TrainingEvent>,
   108→    }
   109→
   110→    impl ExperimentTracker {
   111→        pub fn new() -> Self {
   112→            // 32 is an arbitrary channel size; adjust to throughput needs.
   113→            let (tx, _) = broadcast::channel(32);
   114→            Self {
   115→                state: Arc::new(RwLock::new(HashMap::new())),
   116→                broadcaster: tx,
   117→            }
   118→        }
   119→
   120→        /// Subscribe to training events.
   121→        pub fn subscribe(&self) -> broadcast::Receiver<TrainingEvent> {
   122→            self.broadcaster.subscribe()
   123→        }
   124→
   125→        /// Start a new run with given parameters. Returns run_id.
   126→        pub async fn start_run(
   127→            &self,
   128→            params: HashMap<String, HyperParamValue>,
   129→            tags: Vec<String>,
   130→        ) -> Uuid {
   131→            let run = ExperimentRun {
   132→                run_id: Uuid::new_v4(),
   133→                params,
   134→                start_time: SystemTime::now(),
   135→                end_time: None,
   136→                metrics: HashMap::new(),
   137→                tags,
   138→            };
   139→            let run_id = run.run_id;
   140→            self.state.write().await.insert(run_id, run);
   141→            run_id
   142→        }
   143→
   144→        /// Log metrics for a run & epoch, broadcasting an event.
   145→        pub async fn log_epoch_metrics(
   146→            &self,
   147→            run_id: Uuid,
   148→            epoch: usize,
   149→            metrics: HashMap<String, f64>,
   150→        ) -> Result<(), TunerError> {
   151→            let mut state = self.state.write().await;
   152→            let run = state
   153→                .get_mut(&run_id)
   154→                .ok_or_else(|| TunerError::UnknownRun(run_id))?;
   155→
   156→            // Merge metrics into current map (overwrite duplicates).
   157→            for (k, v) in &metrics {
   158→                run.metrics.insert(k.clone(), *v);
   159→            }
   160→
   161→            let event = TrainingEvent::EpochEnd {
   162→                run_id,
   163→                epoch,
   164→                metrics,
   165→                timestamp: SystemTime::now(),
   166→            };
   167→            let _ = self.broadcaster.send(event); // Ignore if no receivers.
   168→            Ok(())
   169→        }
   170→
   171→        /// Finalize a run, compute its duration & send final event.
   172→        pub async fn end_run(
   173→            &self,
   174→            run_id: Uuid,
   175→            final_metrics: HashMap<String, f64>,
   176→        ) -> Result<(), TunerError> {
   177→            let mut state = self.state.write().await;
   178→            let run = state
   179→                .get_mut(&run_id)
   180→                .ok_or_else(|| TunerError::UnknownRun(run_id))?;
   181→
   182→            run.end_time = Some(SystemTime::now());
   183→            for (k, v) in &final_metrics {
   184→                run.metrics.insert(k.clone(), *v);
   185→            }
   186→
   187→            let duration = run
   188→                .end_time
   189→                .unwrap()
   190→                .duration_since(run.start_time)
   191→                .unwrap_or_default();
   192→
   193→            let event = TrainingEvent::TrainingEnd {
   194→                run_id,
   195→                final_metrics,
   196→                duration,
   197→                timestamp: SystemTime::now(),
   198→            };
   199→            let _ = self.broadcaster.send(event);
   200→            Ok(())
   201→        }
   202→
   203→        /// A cheap read-only snapshot of a completed run.
   204→        pub async fn get_run(&self, run_id: Uuid) -> Option<ExperimentRun> {
   205→            self.state.read().await.get(&run_id).cloned()
   206→        }
   207→    }
   208→}
   209→
   210→// ---------------------------------------------------------------------------
   211→mod tuner {
   212→    use super::*;
   213→
   214→    // ---------------------- Hyper-parameter specification ------------------
   215→    #[derive(Debug, Clone, Serialize, Deserialize)]
   216→    #[serde(untagged)]
   217→    pub enum HyperParamValue {
   218→        Int(i64),
   219→        Float(f64),
   220→        Text(String),
   221→        Flag(bool),
   222→    }
   223→
   224→    impl fmt::Display for HyperParamValue {
   225→        fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
   226→            match self {
   227→                HyperParamValue::Int(v) => write!(f, "{}", v),
   228→                HyperParamValue::Float(v) => write!(f, "{}", v),
   229→                HyperParamValue::Text(v) => write!(f, "{}", v),
   230→                HyperParamValue::Flag(v) => write!(f, "{}", v),
   231→            }
   232→        }
   233→    }
   234→
   235→    /// Parameter space configuration (search domain).
   236→    #[derive(Debug, Clone, Serialize, Deserialize)]
   237→    #[serde(tag = "type", rename_all = "snake_case")]
   238→    pub enum HyperParamSpec {
   239→        IntRange { min: i64, max: i64 },
   240→        FloatRange { min: f64, max: f64 },
   241→        Choice { options: Vec<String> },
   242→        Flag,
   243→    }
   244→
   245→    // -------------------------- Strategy Trait ----------------------------
   246→    #[async_trait::async_trait]
   247→    pub trait HyperParamTuner: Send + Sync {
   248→        /// Produce the next candidate configuration.
   249→        async fn suggest(&self) -> HashMap<String, HyperParamValue>;
   250→
   251→        /// Notify the tuner of the evaluation result so underlying
   252→        /// strategies can update their priors.
   253→        async fn record_result(
   254→            &self,
   255→            params: HashMap<String, HyperParamValue>,
   256→            score: f64,
