    35→/// Domain-level error type.
    36→#[derive(Debug, Error)]
    37→pub enum OrchestratorError {
    38→    #[error("IO error: {0}")]
    39→    Io(#[from] std::io::Error),
    40→
    41→    #[error("HTTP error: {0}")]
    42→    Http(#[from] reqwest::Error),
    43→
    44→    #[error("Serialization error: {0}")]
    45→    Serde(#[from] serde_json::Error),
    46→
    47→    #[error("Broadcast channel error: {0}")]
    48→    BroadcastRecv(#[from] broadcast::error::RecvError),
