    34→/// Common alias for hyper-parameter name/value mapping.
    35→pub type HyperParams = HashMap<String, f64>;
    36→
    37→/// Strategy pattern: A tuner is responsible for suggesting the next set of
    38→/// hyper-parameters *and* ingesting the resulting score so that it can adapt
    39→/// its internal search.
    40→///
    41→/// Implementors must be `Send + Sync` so that the search can be distributed
    42→/// across threads or processes.
    43→///
    44→/// NOTE: The tuner does *not* execute the training job.  That responsibility
    45→/// lies with the `Model Ops` layer.  The tuner is also side-effect free––
    46→/// apart from internal bookkeeping.
    47→pub trait HyperparameterTuner: Send + Sync {
    48→    /// Suggest the next configuration to evaluate.
    49→    fn suggest(&mut self) -> Option<HyperParams>;
    50→
    51→    /// Report the evaluation metric (e.g. accuracy, loss) for a previously
    52→    /// suggested configuration.  Implementations may choose to ignore the
    53→    /// score when the configuration is unknown.
    54→    fn report_result(&mut self, params: &HyperParams, metric: f64);
    55→
    56→    /// Human-readable name; useful for telemetry & debugging.
    57→    fn name(&self) -> &'static str;
    58→}
    59→
    60→/// A simple grid-search tuner that exhaustively evaluates the Cartesian
    61→/// product of discrete candidate values.
    62→///
    63→/// Useful for deterministic sweeps when the search space is small.
    64→pub struct GridSearchTuner {
    65→    grid: Vec<HyperParams>,
    66→    cursor: usize,
    67→}
    68→
    69→impl GridSearchTuner {
    70→    pub fn new(candidates: HashMap<String, Vec<f64>>) -> Self {
    71→        // Compute Cartesian product
    72→        let mut grid: Vec<HyperParams> = vec![];
    73→        Self::cartesian_product(
    74→            &mut grid,
    75→            &mut HyperParams::new(),
    76→            &candidates.into_iter().collect::<Vec<_>>(),
    77→            0,
    78→        );
    79→        info!("GridSearch initialized with {} configurations", grid.len());
    80→        Self { grid, cursor: 0 }
    81→    }
    82→
    83→    fn cartesian_product(
    84→        acc: &mut Vec<HyperParams>,
    85→        current: &mut HyperParams,
    86→        items: &[(String, Vec<f64>)],
    87→        idx: usize,
    88→    ) {
    89→        if idx == items.len() {
    90→            acc.push(current.clone());
    91→            return;
    92→        }
    93→
    94→        let (ref key, ref values) = items[idx];
    95→        for v in values {
    96→            current.insert(key.clone(), *v);
    97→            Self::cartesian_product(acc, current, items, idx + 1);
    98→        }
    99→        current.remove(key);
   100→    }
   101→}
   102→
   103→impl HyperparameterTuner for GridSearchTuner {
   104→    fn suggest(&mut self) -> Option<HyperParams> {
   105→        if self.cursor >= self.grid.len() {
   106→            None
   107→        } else {
   108→            let params = self.grid[self.cursor].clone();
   109→            self.cursor += 1;
   110→            Some(params)
   111→        }
   112→    }
   113→
   114→    fn report_result(&mut self, _params: &HyperParams, _metric: f64) {
   115→        // grid search is stateless; nothing to do.
   116→    }
   117→
   118→    fn name(&self) -> &'static str {
   119→        "GridSearchTuner"
   120→    }
   121→}
