   123→/// Random search tuner that samples uniformly from user-supplied ranges.
   124→/// Each range is inclusive.
   125→///
   126→/// NOTE: For continuous variables, the range is treated as continuous;
   127→/// for discrete variables, the caller can pass equal min==max to achieve
   128→/// deterministic behavior.
   129→pub struct RandomSearchTuner {
   130→    ranges: HashMap<String, (f64, f64)>,
   131→    max_trials: usize,
   132→    trials: usize,
   133→    history: Vec<(HyperParams, f64)>,
   134→}
   135→
   136→impl RandomSearchTuner {
   137→    pub fn new(ranges: HashMap<String, (f64, f64)>, max_trials: usize) -> Self {
   138→        Self {
   139→            ranges,
   140→            max_trials,
   141→            trials: 0,
   142→            history: Vec::new(),
   143→        }
   144→    }
   145→
   146→    fn random_sample(&self) -> HyperParams {
   147→        let mut rng = thread_rng();
   148→        self.ranges
   149→            .iter()
   150→            .map(|(k, (min, max))| (k.clone(), rng.gen_range(*min..=*max)))
   151→            .collect()
   152→    }
   153→}
   154→
   155→impl HyperparameterTuner for RandomSearchTuner {
   156→    fn suggest(&mut self) -> Option<HyperParams> {
   157→        if self.trials >= self.max_trials {
   158→            None
   159→        } else {
   160→            self.trials += 1;
   161→            Some(self.random_sample())
   162→        }
   163→    }
   164→
   165→    fn report_result(&mut self, params: &HyperParams, metric: f64) {
   166→        self.history.push((params.clone(), metric));
   167→    }
   168→
   169→    fn name(&self) -> &'static str {
   170→        "RandomSearchTuner"
   171→    }
   172→}
