   191→/// Observer pattern – The model-training engine emits `TrainingEvent`s that
   192→/// observers can subscribe to.  The tuner implementation itself can be an
   193→/// observer in order to implement adaptive search algorithms such as Bayesian
   194→/// optimization, however, we keep them decoupled so that multiple observers
   195→/// (e.g. loggers, alerting) can co-exist.
   196→#[derive(Debug, Clone)]
   197→pub enum TrainingEvent {
   198→    EpochStart { epoch: u32 },
   199→    EpochEnd {
   200→        epoch: u32,
   201→        metrics: HashMap<String, f64>,
   202→    },
   203→    TrainingFinish {
   204→        best_metric: f64,
   205→        best_params: HyperParams,
   206→    },
   207→}
   208→
   209→/// Observer trait.
   210→pub trait TrainingObserver: Send + Sync {
   211→    fn on_event(&self, event: &TrainingEvent);
   212→}
   213→
   214→/// Default implementation that feeds back the final metric to the tuner.
   215→pub struct TunerObserver {
   216→    tuner: Arc<Mutex<Box<dyn HyperparameterTuner>>>,
   217→}
   218→
   219→impl TunerObserver {
   220→    pub fn new(tuner: Arc<Mutex<Box<dyn HyperparameterTuner>>>) -> Self {
   221→        Self { tuner }
   222→    }
   223→}
   224→
   225→impl TrainingObserver for TunerObserver {
   226→    fn on_event(&self, event: &TrainingEvent) {
   227→        if let TrainingEvent::TrainingFinish {
   228→            best_metric,
   229→            best_params,
   230→        } = event
   231→        {
   232→            if let Ok(mut tuner) = self.tuner.lock() {
   233→                tuner.report_result(best_params, *best_metric);
   234→            } else {
   235→                error!("Unable to lock tuner mutex in observer");
   236→            }
   237→        }
   238→    }
   239→}
