   241→/// Lightweight experiment tracking backed by SQLite.
   242→/// Production deployments can replace this with a more
   243→/// sophisticated store (Postgres, Influx, etc.) via
   244→/// feature flags without changing the public API.
   245→#[derive(Debug)]
   246→pub struct ExperimentTracker {
   247→    db_path: PathBuf,
   248→    conn: Connection,
   249→}
   250→
   251→#[derive(Debug, Serialize, Deserialize)]
   252→pub struct ExperimentRecord {
   253→    pub id: i64,
   254→    pub timestamp: DateTime<Utc>,
   255→    pub tuner_name: String,
   256→    pub params: HyperParams,
   257→    pub metric: f64,
   258→}
   259→
   260→impl ExperimentTracker {
   261→    /// Create a new tracker with the given file path.
   262→    pub fn new<P: AsRef<Path>>(db_path: P) -> Result<Self> {
   263→        let conn = Connection::open(&db_path)
   264→            .with_context(|| format!("opening experiments db {:?}", db_path.as_ref()))?;
   265→
   266→        let tracker = Self {
   267→            db_path: db_path.as_ref().to_path_buf(),
   268→            conn,
   269→        };
   270→
   271→        tracker.init_schema()?;
   272→        Ok(tracker)
   273→    }
   274→
   275→    fn init_schema(&self) -> Result<()> {
   276→        self.conn.execute_batch(
   277→            "
   278→            CREATE TABLE IF NOT EXISTS experiments (
   279→                id          INTEGER PRIMARY KEY AUTOINCREMENT,
   280→                timestamp   TEXT NOT NULL,
   281→                tuner_name  TEXT NOT NULL,
   282→                params      BLOB NOT NULL,
   283→                metric      REAL NOT NULL
   284→            );
   285→            ",
   286→        )?;
   287→        Ok(())
   288→    }
   289→
   290→    /// Persist an experiment record.
   291→    pub fn log_record(&self, tuner_name: &str, params: &HyperParams, metric: f64) -> Result<i64> {
   292→        let timestamp: DateTime<Utc> = Utc::now();
   293→        let params_blob = serde_json::to_vec(params).context("serializing hyperparams")?;
   294→
   295→        self.conn.execute(
   296→            "
   297→            INSERT INTO experiments (timestamp, tuner_name, params, metric)
   298→            VALUES (?1, ?2, ?3, ?4);
   299→            ",
   300→            params![
   301→                timestamp.to_rfc3339(),
   302→                tuner_name,
   303→                params_blob,
   304→                metric
   305→            ],
   306→        )?;
   307→
   308→        Ok(self.conn.last_insert_rowid())
   309→    }
   310→
   311→    /// Retrieve all experiments for auditing or analytics.
   312→    pub fn all_records(&self) -> Result<Vec<ExperimentRecord>> {
   313→        let mut stmt = self.conn.prepare(
   314→            "
   315→            SELECT id, timestamp, tuner_name, params, metric
   316→            FROM experiments
   317→            ORDER BY id ASC;
   318→            ",
   319→        )?;
   320→
   321→        let iter = stmt.query_map([], |row| {
   322→            let params_blob: Vec<u8> = row.get(3)?;
   323→            let params: HyperParams = serde_json::from_slice(&params_blob)
   324→                .map_err(|e| rusqlite::Error::FromSqlConversionFailure(3, rusqlite::types::Type::Blob, Box::new(e)))?;
   325→
   326→            Ok(ExperimentRecord {
   327→                id: row.get(0)?,
   328→                timestamp: DateTime::parse_from_rfc3339(&row.get::<_, String>(1)?)
   329→                    .map(|dt| dt.with_timezone(&Utc))
   330→                    .map_err(|e| rusqlite::Error::FromSqlConversionFailure(1, rusqlite::types::Type::Text, Box::new(e)))?,
   331→                tuner_name: row.get(2)?,
   332→                params,
   333→                metric: row.get(4)?,
   334→            })
   335→        })?;
   336→
   337→        let mut out = Vec::new();
   338→        for rec in iter {
   339→            out.push(rec?);
   340→        }
   341→        Ok(out)
   342→    }
   343→}
