   345→/// Example of orchestrating an end-to-end hyper-parameter tuning session.
   346→/// The function is *sync* for brevity but can be made async using
   347→/// `tokio::task::spawn_blocking` or similar.
   348→///
   349→/// NOTE: This is *not* executed automatically; it serves as a reference
   350→/// implementation for higher-level orchestration code.
   351→pub fn run_hpo_session() -> Result<()> {
   352→    // ------------------------------------------
   353→    // Create the tuner (here: grid search)
   354→    // ------------------------------------------
   355→    let mut candidates: HashMap<String, Vec<f64>> = HashMap::new();
   356→    candidates.insert("learning_rate".into(), vec![0.01, 0.001]);
   357→    candidates.insert("dropout".into(), vec![0.1, 0.2, 0.3]);
   358→
   359→    let tuner: Arc<Mutex<Box<dyn HyperparameterTuner>>> =
   360→        Arc::new(Mutex::new(TunerFactory::make_grid_search(candidates)));
   361→
   362→    // ------------------------------------------
   363→    // Initialize experiment tracker
   364→    // ------------------------------------------
   365→    let tracker = ExperimentTracker::new("experiments.db")?;
   366→
   367→    // ------------------------------------------
   368→    // Main loop
   369→    // ------------------------------------------
   370→    loop {
   371→        let next_params = {
   372→            let mut tuner = tuner.lock().expect("tuner lock poisoned");
   373→            tuner.suggest()
   374→        };
   375→
   376→        let Some(params) = next_params else {
   377→            info!("Hyper-parameter search complete.");
   378→            break;
   379→        };
   380→
   381→        // ------------------------------------------------------------------
   382→        // >>>>  In the real system, `train_model()` would kick off an *async*
   383→        // >>>>  training job, possibly on a GPU worker pool and stream back
   384→        // >>>>  metrics over a channel.  For demonstration, we simulate a
   385→        // >>>>  random metric here.
   386→        // ------------------------------------------------------------------
   387→        let simulated_metric: f64 = thread_rng().gen_range(0.7..0.99);
   388→
   389→        // Feed the result back into the tuner *and* log it to the tracker.
   390→        {
   391→            let mut tuner_locked = tuner.lock().expect("tuner lock poisoned");
   392→            tuner_locked.report_result(&params, simulated_metric);
   393→        }
   394→
   395→        tracker
   396→            .log_record("GridSearchTuner", &params, simulated_metric)
   397→            .context("logging experiment")?;
   398→
   399→        debug!(
   400→            "Evaluated {:?} -> metric = {:.4}",
   401→            &params, simulated_metric
   402→        );
   403→    }
   404→
   405→    Ok(())
   406→}
