   126→impl Subject for ModelMonitor {
   127→    fn register_observer(&mut self, obs: Arc<dyn Observer>) {
   128→        let mut guard = self
   129→            .observers
   130→            .write()
   131→            .expect("ModelMonitor observer lock poisoned");
   132→        guard.push(obs);
   133→    }
   134→
   135→    fn deregister_observer(&mut self, obs_id: usize) {
   136→        let mut guard = self
   137→            .observers
   138→            .write()
   139→            .expect("ModelMonitor observer lock poisoned");
   140→        if obs_id < guard.len() {
   141→            guard.remove(obs_id);
   142→        }
   143→    }
   144→
   145→    fn notify(&self, event: ModelEvent) {
   146→        let guard = self
   147→            .observers
   148→            .read()
   149→            .expect("ModelMonitor observer lock poisoned");
   150→        for obs in guard.iter() {
   151→            // Fire & forget; each observer must handle its own failure modes
   152→            let evt = event.clone();
   153→            let obs = Arc::clone(obs);
   154→            task::spawn(async move {
   155→                if let Err(e) = obs.on_event(&evt) {
   156→                    eprintln!("Observer failed to handle event: {e}");
   157→                }
   158→            });
   159→        }
   160→    }
   161→}
