     2→//! Module 55 ­— Hyper-parameter Tuning & Experiment Tracking
     3→//! ---------------------------------------------------------
     4→//! This module contains the implementation of the Strategy‐based hyper-parameter
     5→//! tuner as well as a lightweight Observer for experiment tracking.  Although
     6→//! the production project offers many more knobs, this file provides a realistic
     7→//! slice that can be embedded directly into the VisuTility Orchestrator.
     8→//!
     9→//! Architectural Patterns Demonstrated
    10→//! * Strategy Pattern    – `TunerStrategy` trait + concrete tuners
    11→//! * Factory  Pattern    – `TunerFactory` for late-bound instantiation
    12→//! * Observer Pattern    – `ExperimentEvent`  + `ExperimentObserver`
    13→//! * Pipeline  Pattern    – `run_hyperparameter_tuning` async pipeline
    14→//!
    15→//! External Crates
    16→//! * `rand`              – random search strategy
    17→//! * `tokio`             – async execution
    18→//! * `serde`, `serde_json` – (De)serialising trial metadata
    19→//! * `thiserror`         – ergonomic error definitions
    20→
    21→// --------------------------- Dependency Imports ------------------------------
    22→use rand::{rngs::StdRng, seq::IteratorRandom, Rng, SeedableRng};
    23→use serde::{Deserialize, Serialize};
    24→use std::{
    25→    collections::HashMap,
    26→    fmt::Debug,
    27→    sync::{Arc, Mutex},
    28→    time::Instant,
    29→};
    30→use thiserror::Error;
    31→use tokio::task;
    32→
    33→// ---------------------------- Error Definition -------------------------------
    34→#[derive(Debug, Error)]
    35→pub enum TuningError {
    36→    #[error("model training failed: {0}")]
    37→    TrainFailure(String),
    38→    #[error("invalid hyper-parameter space: {0}")]
    39→    InvalidSpace(String),
    40→    #[error("internal error: {0}")]
    41→    Internal(String),
    42→}
    43→
    44→// ------------------------- Trainable Model Abstraction -----------------------
    45→/// A minimal contract that every model inside VisuTility needs to implement
    46→/// in order to participate in automated tuning.
    47→pub trait Trainable: Send + Sync + Debug + 'static {
    48→    /// User-level hyper-parameter type.
    49→    type HyperParams: Serialize + for<'de> Deserialize<'de> + Send + Sync + Clone + Debug;
    50→    /// Metric returned by evaluation.
    51→    type Metric: PartialOrd + Copy + Debug;
    52→
    53→    /// Create a new model instance with the supplied hyper-parameters.
    54→    fn new(params: &Self::HyperParams) -> Result<Self, TuningError>
    55→    where
    56→        Self: Sized;
    57→
    58→    /// Train the model on given data split.
    59→    fn train(&mut self, dataset: DatasetView) -> Result<(), TuningError>;
    60→
    61→    /// Validate the model and return a metric (higher is better).
    62→    fn validate(&self, dataset: DatasetView) -> Result<Self::Metric, TuningError>;
    63→}
    64→
    65→// ----------------------------- Data Contracts --------------------------------
    66→/// A lightweight view over a data split.
    67→///
    68→/// NOTE: In the real platform this is a zero-copy view into an Arrow Flight
    69→/// stream.  For brevity, we merely keep a string ID here.
    70→#[derive(Clone, Debug)]
    71→pub struct DatasetView {
    72→    pub id: String,
    73→}
    74→
    75→// ------------------------------ Experiment I/O -------------------------------
    76→#[derive(Debug, Clone, Serialize, Deserialize)]
    77→pub struct TrialRecord<M: Trainable> {
    78→    pub params: M::HyperParams,
    79→    pub metric: M::Metric,
    80→    pub duration_ms: u128,
    81→}
    82→
    83→/// Event emitted by the tuning engine.
    84→#[derive(Debug, Clone)]
    85→pub enum ExperimentEvent<M: Trainable> {
    86→    TrialStarted(M::HyperParams),
    87→    TrialCompleted(TrialRecord<M>),
    88→    TuningFinished(Option<TrialRecord<M>>),
    89→}
    90→
    91→/// Observer interface (pull-based is also supported in other modules).
    92→pub trait ExperimentObserver<M: Trainable>: Send + Sync {
    93→    fn on_event(&self, event: ExperimentEvent<M>);
    94→}
    95→
    96→/// Thread-safe, in-memory observer used in tests and local runs.
    97→#[derive(Default)]
    98→pub struct InMemoryObserver<M: Trainable> {
    99→    events: Arc<Mutex<Vec<ExperimentEvent<M>>>>,
   100→}
   101→impl<M: Trainable> InMemoryObserver<M> {
   102→    pub fn events(&self) -> Vec<ExperimentEvent<M>> {
   103→        self.events.lock().unwrap().clone()
   104→    }
   105→}
   106→impl<M: Trainable> ExperimentObserver<M> for InMemoryObserver<M> {
   107→    fn on_event(&self, event: ExperimentEvent<M>) {
   108→        self.events.lock().unwrap().push(event);
   109→    }
   110→}
   111→
   112→// ----------------------------- Tuner Strategy --------------------------------
   113→pub trait TunerStrategy<M: Trainable>: Send + Sync {
   114→    /// Run the tuning loop and return the best trial record (if any).
   115→    fn tune(
   116→        &self,
   117→        space: HyperParamSpace<M>,
   118→        dataset: DatasetView,
   119→        observers: &[Arc<dyn ExperimentObserver<M>>],
   120→    ) -> Result<Option<TrialRecord<M>>, TuningError>;
   121→}
   122→
   123→/// Hyper-parameter search space.
   124→///
   125→/// In the real system this would allow conditional spaces, distributions,
   126→/// nested structures, etc.  Here we simply map parameter names to candidate
   127→/// categorical values.
   128→#[derive(Clone)]
   129→pub struct HyperParamSpace<M: Trainable> {
   130→    choices: HashMap<String, Vec<serde_json::Value>>,
   131→    _phantom: std::marker::PhantomData<M>,
   132→}
   133→impl<M: Trainable> HyperParamSpace<M> {
   134→    pub fn new() -> Self {
   135→        Self {
   136→            choices: HashMap::new(),
   137→            _phantom: std::marker::PhantomData,
   138→        }
   139→    }
   140→
   141→    pub fn add_choice<T: Serialize>(&mut self, name: &str, values: Vec<T>) {
   142→        self.choices.insert(
   143→            name.to_owned(),
   144→            values
   145→                .into_iter()
   146→                .map(|v| serde_json::to_value(v).expect("serialise hyper-param"))
   147→                .collect(),
   148→        );
   149→    }
   150→
   151→    fn enumerate_grid(&self) -> Vec<M::HyperParams> {
   152→        // A naïve Cartesian product enumerator. Usually replaced by an iterator
   153→        // that yields lazily to avoid combinatorial explosion.
   154→        let mut param_maps: Vec<HashMap<String, serde_json::Value>> = vec![HashMap::new()];
   155→
   156→        for (key, choices) in &self.choices {
   157→            let mut next_maps = Vec::new();
   158→            for choice in choices {
   159→                for base in &param_maps {
   160→                    let mut map = base.clone();
   161→                    map.insert(key.clone(), choice.clone());
   162→                    next_maps.push(map);
   163→                }
   164→            }
   165→            param_maps = next_maps;
   166→        }
   167→
   168→        param_maps
   169→            .into_iter()
   170→            .map(|map| serde_json::from_value::<M::HyperParams>(serde_json::Value::Object(
   171→                map.into_iter().collect(),
   172→            ))
   173→            .expect("convert to HyperParams"))
   174→            .collect()
   175→    }
   176→
   177→    fn pick_random(&self, rng: &mut StdRng) -> Option<M::HyperParams> {
   178→        let mut map = HashMap::<String, serde_json::Value>::new();
   179→        for (k, choices) in &self.choices {
   180→            let choice = choices.iter().choose(rng)?;
   181→            map.insert(k.clone(), choice.clone());
   182→        }
   183→        serde_json::from_value(serde_json::Value::Object(map.into_iter().collect())).ok()
   184→    }
   185→}
   186→
   187→// --------------------- Concrete Strategies ----------------------------------
   188→pub struct GridSearchTuner;
   189→impl<M: Trainable> TunerStrategy<M> for GridSearchTuner {
   190→    fn tune(
   191→        &self,
   192→        space: HyperParamSpace<M>,
   193→        dataset: DatasetView,
   194→        observers: &[Arc<dyn ExperimentObserver<M>>],
   195→    ) -> Result<Option<TrialRecord<M>>, TuningError> {
   196→        let mut best: Option<TrialRecord<M>> = None;
   197→
   198→        for params in space.enumerate_grid() {
   199→            notify(observers, ExperimentEvent::TrialStarted(params.clone()));
   200→            let start = Instant::now();
   201→
   202→            let mut model = M::new(&params)?;
   203→            model.train(dataset.clone())?;
   204→            let metric = model.validate(dataset.clone())?;
   205→
   206→            let record = TrialRecord {
   207→                params: params.clone(),
   208→                metric,
   209→                duration_ms: start.elapsed().as_millis(),
   210→            };
   211→            notify(observers, ExperimentEvent::TrialCompleted(record.clone()));
   212→
   213→            if best.as_ref().map(|b| metric > b.metric).unwrap_or(true) {
   214→                best = Some(record);
   215→            }
   216→        }
   217→
   218→        notify(observers, ExperimentEvent::TuningFinished(best.clone()));
   219→        Ok(best)
   220→    }
   221→}
   222→
   223→pub struct RandomSearchTuner {
   224→    trials: usize,
   225→    seed: u64,
   226→}
   227→impl RandomSearchTuner {
   228→    pub fn new(trials: usize, seed: u64) -> Self {
   229→        Self { trials, seed }
   230→    }
   231→}
   232→impl<M: Trainable> TunerStrategy<M> for RandomSearchTuner {
   233→    fn tune(
   234→        &self,
   235→        space: HyperParamSpace<M>,
   236→        dataset: DatasetView,
   237→        observers: &[Arc<dyn ExperimentObserver<M>>],
   238→    ) -> Result<Option<TrialRecord<M>>, TuningError> {
   239→        let mut best: Option<TrialRecord<M>> = None;
   240→        let mut rng = StdRng::seed_from_u64(self.seed);
   241→
   242→        for _ in 0..self.trials {
   243→            let params = match space.pick_random(&mut rng) {
