     2→//! Hyper-parameter Tuning Engine
     3→//!
     4→//! This module implements a Strategy-Pattern–based hyper-parameter tuning
     5→//! engine that can be plugged into any stage of the VisuTility Orchestrator
     6→//! pipeline. The engine provides:
     7→//!   • A generic [`Tuner`] façade that coordinates trial execution
     8→//!   • Pluggable tuning strategies (e.g. Grid, Random, Bayesian)
     9→//!   • Observer hooks for experiment tracking & early-stopping
    10→//!
    11→//! The code purposefully avoids project-specific dependencies so it can be
    12→//! re-used by other crates within the workspace. All heavy lifting (model
    13→//! compilation, dataset loading, etc.) is delegated to an [`Objective`]
    14→//! implementation supplied by the caller.
    15→
    16→use std::collections::HashMap;
    17→use std::fmt;
    18→use std::sync::{Arc, Mutex};
    19→use std::time::{Duration, Instant};
    20→
    21→use crossbeam_channel::{unbounded, Receiver, Sender};
    22→use rand::distributions::{Distribution, Uniform};
    23→use rand::{rngs::StdRng, SeedableRng};
    24→use serde::{Deserialize, Serialize};
    25→use thiserror::Error;
    26→
    27→/// Generic error type for the tuning engine.
    28→#[derive(Debug, Error)]
    29→pub enum TuningError {
    30→    #[error("objective function failed: {0}")]
    31→    ObjectiveFailed(String),
    32→
    33→    #[error("invalid parameter space definition: {0}")]
    34→    InvalidParameter(String),
    35→
    36→    #[error("I/O error: {0}")]
    37→    Io(#[from] std::io::Error),
    38→
    39→    #[error("serialization error: {0}")]
    40→    Serde(#[from] serde_json::Error),
    41→}
    42→
    43→/// Domain of a single hyper-parameter.
    44→///
    45→/// The enum is intentionally limited to float & discrete types to keep the
    46→/// sample code concise. In production you may want Boolean, Categorical, etc.
    47→#[derive(Clone, Debug, Serialize, Deserialize)]
    48→pub enum ParameterDomain {
    49→    Continuous { low: f64, high: f64 },
    50→    Discrete(Vec<f64>),
    51→}
    52→
    53→impl ParameterDomain {
    54→    /// Sample a value from the domain.
    55→    fn sample<R: rand::Rng>(&self, rng: &mut R) -> f64 {
    56→        match self {
    57→            ParameterDomain::Continuous { low, high } => {
    58→                let distr = Uniform::new(*low, *high);
    59→                distr.sample(rng)
    60→            }
    61→            ParameterDomain::Discrete(values) => {
    62→                let idx = rng.gen_range(0..values.len());
    63→                values[idx]
    64→            }
    65→        }
    66→    }
    67→
    68→    /// Iterate over all discrete points when applicable.
    69→    fn iter(&self) -> Option<impl Iterator<Item = f64> + '_> {
    70→        match self {
    71→            ParameterDomain::Discrete(values) => Some(values.iter().copied()),
    72→            _ => None,
    73→        }
    74→    }
    75→}
    76→
    77→/// Collection of named domains.
    78→pub type ParameterSpace = HashMap<String, ParameterDomain>;
    79→
    80→/// Concrete set of hyper-parameters for a single trial.
    81→pub type HyperParams = HashMap<String, f64>;
    82→
    83→/// Result produced by a single trial.
    84→#[derive(Clone, Debug, Serialize, Deserialize)]
    85→pub struct TrialResult {
    86→    pub params: HyperParams,
    87→    pub score: f64,
    88→    pub duration: Duration,
    89→}
    90→
    91→/// Contract for objective evaluation.
    92→///
    93→/// Implementors should train a model (or a down-scaled proxy) and return the
    94→/// metric that the tuning process must optimize (higher is better).
    95→pub trait Objective: Send + Sync + 'static {
    96→    fn evaluate(&self, params: &HyperParams) -> Result<f64, TuningError>;
    97→}
    98→
    99→/// Observer pattern for side-effects such as logging, experiment tracking,
   100→/// early stopping, etc.
   101→pub trait TuningObserver: Send + Sync {
   102→    fn on_trial_completed(&self, result: &TrialResult);
   103→}
   104→
   105→/// Strategy pattern for search algorithms.
   106→pub trait TuningStrategy: Send + Sync {
   107→    fn next_parameters(&mut self) -> Option<HyperParams>;
   108→    fn register_result(&mut self, _result: &TrialResult) {}
   109→}
   110→
   111→/// Grid Search implementation.
   112→///
   113→/// Explores the cartesian product of every discrete domain, *ignoring*
   114→/// continuous ones. If the user provides only continuous spaces, the grid is
   115→/// empty and `next_parameters` will always return `None`.
   116→pub struct GridSearch {
   117→    grid: Vec<HyperParams>,
   118→    cursor: usize,
   119→}
   120→
   121→impl GridSearch {
   122→    pub fn new(space: &ParameterSpace) -> Self {
   123→        let mut grid: Vec<HyperParams> = vec![HyperParams::new()];
   124→        for (name, domain) in space {
   125→            if let Some(iter) = domain.iter() {
   126→                let mut next_grid = Vec::with_capacity(grid.len() * 4);
   127→                for existing in &grid {
   128→                    for value in iter.clone() {
   129→                        let mut params = existing.clone();
   130→                        params.insert(name.clone(), value);
   131→                        next_grid.push(params);
   132→                    }
   133→                }
   134→                grid = next_grid;
   135→            }
   136→        }
   137→        Self { grid, cursor: 0 }
   138→    }
   139→}
   140→
   141→impl TuningStrategy for GridSearch {
   142→    fn next_parameters(&mut self) -> Option<HyperParams> {
   143→        if self.cursor < self.grid.len() {
   144→            let params = self.grid[self.cursor].clone();
   145→            self.cursor += 1;
   146→            Some(params)
   147→        } else {
   148→            None
   149→        }
   150→    }
   151→}
   152→
   153→/// Random Search implementation using a seeded PRNG.
   154→pub struct RandomSearch {
   155→    space: ParameterSpace,
   156→    rng: StdRng,
   157→    max_trials: usize,
   158→    generated: usize,
   159→}
   160→
   161→impl RandomSearch {
   162→    pub fn new(space: ParameterSpace, max_trials: usize, seed: u64) -> Self {
   163→        Self {
   164→            space,
   165→            rng: StdRng::seed_from_u64(seed),
   166→            max_trials,
   167→            generated: 0,
   168→        }
   169→    }
   170→}
   171→
   172→impl TuningStrategy for RandomSearch {
   173→    fn next_parameters(&mut self) -> Option<HyperParams> {
   174→        if self.generated >= self.max_trials {
   175→            return None;
   176→        }
   177→        let mut params = HyperParams::with_capacity(self.space.len());
   178→        for (name, domain) in &self.space {
   179→            params.insert(name.clone(), domain.sample(&mut self.rng));
   180→        }
   181→        self.generated += 1;
   182→        Some(params)
   183→    }
   184→}
   185→
   186→/// Thread-safe experiment tracker that writes each trial to a JSON Lines file.
   187→/// The implementation is intentionally simple and can be replaced by something
   188→/// like MLflow, Weights & Biases, or a SQL database.
   189→pub struct JsonlTracker {
   190→    file: Arc<Mutex<std::fs::File>>,
   191→}
   192→
   193→impl JsonlTracker {
   194→    pub fn new(path: impl AsRef<std::path::Path>) -> Result<Self, TuningError> {
   195→        let file = std::fs::OpenOptions::new()
   196→            .create(true)
   197→            .append(true)
   198→            .open(path)?;
   199→        Ok(Self {
   200→            file: Arc::new(Mutex::new(file)),
   201→        })
   202→    }
   203→}
   204→
   205→impl TuningObserver for JsonlTracker {
   206→    fn on_trial_completed(&self, result: &TrialResult) {
   207→        if let Ok(serialized) = serde_json::to_string(result) {
   208→            if let Ok(mut file) = self.file.lock() {
   209→                // Ignore I/O errors so tuning can proceed.
   210→                let _ = writeln!(file, "{}", serialized);
   211→            }
   212→        }
   213→    }
   214→}
   215→
   216→/// Central façade that orchestrates strategy, observers and objective.
   217→pub struct Tuner<S: TuningStrategy> {
   218→    strategy: S,
   219→    objective: Arc<dyn Objective>,
   220→    observers: Vec<Arc<dyn TuningObserver>>,
   221→    tx: Sender<TrialResult>,
   222→    rx: Receiver<TrialResult>,
   223→}
   224→
   225→impl<S: TuningStrategy> Tuner<S> {
   226→    pub fn builder(strategy: S, objective: Arc<dyn Objective>) -> TunerBuilder<S> {
   227→        TunerBuilder::new(strategy, objective)
   228→    }
   229→
   230→    fn new(strategy: S, objective: Arc<dyn Objective>, observers: Vec<Arc<dyn TuningObserver>>) -> Self {
   231→        let (tx, rx) = unbounded();
   232→        Self {
   233→            strategy,
   234→            objective,
   235→            observers,
   236→            tx,
   237→            rx,
   238→        }
   239→    }
   240→
   241→    /// Drives the tuning loop until the strategy is exhausted or an error
   242→    /// occurs. Returns the best trial encountered.
   243→    pub fn run(&mut self) -> Result<TrialResult, TuningError> {
   244→        let mut best: Option<TrialResult> = None;
   245→
   246→        // Spawn a simple worker thread pool (1 thread / logical core).
   247→        let n_workers = num_cpus::get();
   248→        let mut handles = Vec::with_capacity(n_workers);
   249→        for _ in 0..n_workers {
   250→            let tx = self.tx.clone();
   251→            let objective = self.objective.clone();
   252→            let mut local_strategy = &mut self.strategy as *mut S; // raw ptr to share across threads
   253→            handles.push(std::thread::spawn(move || loop {
   254→                // SAFETY: Exclusive access is guaranteed by the global lock below.
   255→                let params = {
   256→                    // Strategy access is synchronized via a global mutex.
   257→                    static STRATEGY_LOCK: once_cell::sync::Lazy<Mutex<()>> =
   258→                        once_cell::sync::Lazy::new(|| Mutex::new(()));
   259→                    let _guard = STRATEGY_LOCK.lock().unwrap();
   260→                    // Mutable borrow of the strategy behind the raw pointer.
