   195→//
   196→
   197→/// Trait for observers interested in metric updates.
   198→pub trait MetricsObserver: Send {
   199→    /// Called whenever new training metrics are recorded.
   200→    fn on_metrics_update(&mut self, metrics: &TrainingMetrics);
   201→}
   202→
   203→/// Concrete observer that monitors metrics & pushes [`RetrainEvent`]s.
   204→pub struct PerformanceMonitor {
   205→    history: VecDeque<TrainingMetrics>,
   206→    window: usize,
   207→    threshold_pct: f32,
   208→    tx_retrain: Sender<RetrainEvent>,
   209→    model_id: String,
   210→}
   211→
   212→impl PerformanceMonitor {
   213→    /// Create a new monitor.
   214→    ///
   215→    /// * `window` – number of recent metrics used to compute rolling mean.
   216→    /// * `threshold_pct` – acceptable degradation percentage vs. best.
   217→    pub fn new(
   218→        model_id: String,
   219→        window: usize,
   220→        threshold_pct: f32,
   221→        tx_retrain: Sender<RetrainEvent>,
   222→    ) -> Self {
   223→        Self {
   224→            history: VecDeque::with_capacity(window),
   225→            window,
   226→            threshold_pct,
   227→            tx_retrain,
   228→            model_id,
   229→        }
   230→    }
   231→
   232→    /// Computes moving average loss over the internal window.
   233→    fn avg_loss(&self) -> Option<f32> {
   234→        if self.history.is_empty() {
   235→            return None;
   236→        }
   237→        Some(
   238→            self.history
   239→                .iter()
   240→                .map(|m| m.loss)
   241→                .sum::<f32>()
   242→                / self.history.len() as f32,
   243→        )
   244→    }
   245→}
   246→
   247→impl MetricsObserver for PerformanceMonitor {
   248→    fn on_metrics_update(&mut self, metrics: &TrainingMetrics) {
   249→        // Maintain bounded window.
   250→        if self.history.len() == self.window {
   251→            self.history.pop_front();
   252→        }
   253→        self.history.push_back(*metrics);
   254→
   255→        // Compute rolling avg and detect degradation.
   256→        if let Some(avg_loss) = self.avg_loss() {
   257→            let worst_allowed = avg_loss * (1.0 + self.threshold_pct);
   258→            if metrics.loss > worst_allowed {
   259→                // Push retrain event.
   260→                let evt = RetrainEvent {
   261→                    model_id: self.model_id.clone(),
   262→                    reason: format!(
   263→                        "Loss degraded {:.2}% vs. rolling mean",
   264→                        (metrics.loss / avg_loss - 1.0) * 100.0
   265→                    ),
   266→                };
   267→                // It's okay to ignore send errors — they indicate closed consumer.
   268→                let _ = self.tx_retrain.send(evt);
   269→            }
   270→        }
   271→    }
   272→}
