   278→/// Coordinator that glues together tuner, observer, and async channels.
   279→///
   280→/// It represents a coarse-grained task that would likely run in a Tokio
   281→/// executor in the real orchestrator; here we model it with plain threads
   282→/// for minimal dependencies.
   283→///
   284→/// The loop:
   285→/// 1. Consumes new metrics from `rx_metrics`.
   286→/// 2. Feeds them to the tuner.
   287→/// 3. Broadcasts them to observers.
   288→/// 4. Emits new hyper-parameter configs via `tx_config`.
   289→pub struct TuningCoordinator {
   290→    tuner: Mutex<Box<dyn HyperparameterTuner>>,
   291→    observers: Mutex<Vec<Box<dyn MetricsObserver>>>,
   292→    rx_metrics: Receiver<(HyperParameterConfig, TrainingMetrics)>,
   293→    tx_config: Sender<HyperParameterConfig>,
   294→}
   295→
   296→impl TuningCoordinator {
   297→    #[allow(clippy::too_many_arguments)]
   298→    pub fn new(
   299→        tuner: Box<dyn HyperparameterTuner>,
   300→        observers: Vec<Box<dyn MetricsObserver>>,
   301→        rx_metrics: Receiver<(HyperParameterConfig, TrainingMetrics)>,
   302→        tx_config: Sender<HyperParameterConfig>,
   303→    ) -> Arc<Self> {
   304→        Arc::new(Self {
   305→            tuner: Mutex::new(tuner),
   306→            observers: Mutex::new(observers),
   307→            rx_metrics,
   308→            tx_config,
   309→        })
   310→    }
   311→
   312→    /// Blocking loop; should be spawned on its own thread / executor.
   313→    pub fn start(self: Arc<Self>) {
   314→        std::thread::spawn(move || {
   315→            let ticker = tick(Duration::from_secs(1));
   316→
   317→            loop {
   318→                select! {
   319→                    recv(self.rx_metrics) -> msg => {
   320→                        match msg {
   321→                            Ok((cfg, metrics)) => {
   322→                                // 1) Produce new config via tuner.
   323→                                let mut tuner = self.tuner.lock().expect("poisoned lock");
   324→                                match tuner.tune(&cfg, &metrics) {
   325→                                    Ok(new_cfg) => {
   326→                                        // Send back to upstream training service
   327→                                        if let Err(err) = self.tx_config.send(new_cfg) {
   328→                                            eprintln!("TuningCoordinator: failed to send new config: {err}");
   329→                                        }
   330→                                    }
   331→                                    Err(e) => eprintln!("TuningCoordinator: tune() failed: {e:?}"),
   332→                                }
   333→
   334→                                // 2) Notify observers.
   335→                                for obs in self.observers.lock().expect("poisoned lock").iter_mut() {
   336→                                    obs.on_metrics_update(&metrics);
   337→                                }
   338→                            }
   339→                            Err(_) => {
   340→                                // Upstream closed. Shutdown gracefully.
   341→                                break;
   342→                            }
   343→                        }
   344→                    }
   345→                    recv(ticker) -> _ => {
   346→                        // Heart-beat for logging / metrics integration.
   347→                        // In prod we would emit metrics to Prometheus here.
   348→                    }
   349→                }
   350→            }
   351→        });
   352→    }
   353→}
