     2→//! src/module_43.rs
     3→//! --------------------------------------------------------------
     4→//! Model-Monitoring & Automated-Retraining Orchestrator
     5→//! --------------------------------------------------------------
     6→//! This module wires together the Observer & Strategy patterns used by the
     7→//! VisuTility Orchestrator to
     8→//!   1. observe live model-serving metrics,
     9→//!   2. detect statistical drift or performance regressions, and
    10→//!   3. trigger an automated retraining job through the internal MLOps
    11→//!      pipeline when necessary.
    12→//!
    13→//! It is fully self-contained and agnostic of the concrete metric backend,
    14→//! storage layer, or experiment-tracking implementation.  All of those
    15→//! concerns are injected via trait objects, keeping the module easily
    16→//! testable and reusable across binaries and workspaces.
    17→
    18→use std::collections::VecDeque;
    19→use std::sync::{Arc, Mutex};
    20→use std::time::{Duration, Instant};
    21→
    22→use log::{debug, error, info, warn};
    23→use thiserror::Error;
    24→
    25→/// A normalized metric payload emitted by the Serving-Ops layer.
    26→///
    27→/// Requirements:
    28→///   • `value` MUST be normalized so that higher is always better.  
    29→///   • `timestamp` must be captured close to the model to guarantee
    30→///     time-series fidelity even in presence of network jitter.
    31→#[derive(Debug, Clone)]
    32→pub struct MetricSample {
    33→    pub metric_name: String,
    34→    pub value: f64,
    35→    pub timestamp: Instant,
    36→}
    37→
    38→/// Errors surfaced by the Model Monitor and its collaborators.
    39→#[derive(Debug, Error)]
    40→pub enum MonitorError {
    41→    #[error("observer failed: {0}")]
    42→    ObserverFailure(String),
    43→    #[error("strategy evaluation failed: {0}")]
    44→    StrategyFailure(String),
    45→}
    46→
    47→/// Trait implemented by components interested in real-time metric updates
    48→/// (dashboards, alarm systems, audit logs, …).
    49→pub trait MetricObserver: Send + Sync + 'static {
    50→    fn on_metric(&self, sample: &MetricSample) -> Result<(), MonitorError>;
    51→}
    52→
    53→/// Decision returned by a retraining strategy after evaluating a metric window.
    54→#[derive(Debug, Clone, Copy, PartialEq)]
    55→pub enum RetrainingDecision {
    56→    NoAction,
    57→    ShouldRetrain,
    58→}
    59→
    60→/// Strategy that evaluates a sliding window of metrics and decides whether
    61→/// automated retraining should be triggered.
    62→///
    63→/// Implementations MUST be thread-safe and cheap to clone: they are wrapped
    64→/// in `Arc` internally.
    65→pub trait RetrainingStrategy: Send + Sync + 'static {
    66→    fn evaluate(
    67→        &self,
    68→        metric_name: &str,
    69→        window: &[MetricSample],
    70→    ) -> Result<RetrainingDecision, MonitorError>;
    71→}
    72→
    73→/// A statistically-driven strategy that triggers retraining when the average
    74→/// of the last `window_size` samples drops below `min_acceptable_score`.
    75→///
    76→/// Example:
    77→///   For an F1-score in [0,1] you may want to trigger retraining once the
    78→///   average score of the last 10 samples falls under 0.80.
    79→pub struct StatisticalAverageStrategy {
    80→    min_acceptable_score: f64,
    81→    window_size: usize,
    82→}
    83→
    84→impl StatisticalAverageStrategy {
    85→    pub fn new(min_acceptable_score: f64, window_size: usize) -> Self {
    86→        assert!(
    87→            (0.0..=1.0).contains(&min_acceptable_score),
    88→            "min_acceptable_score must be in [0,1]"
    89→        );
    90→        assert!(window_size > 1, "window_size must be > 1");
    91→
    92→        Self {
    93→            min_acceptable_score,
    94→            window_size,
    95→        }
    96→    }
    97→}
    98→
    99→impl RetrainingStrategy for StatisticalAverageStrategy {
   100→    fn evaluate(
   101→        &self,
   102→        _metric_name: &str,
   103→        window: &[MetricSample],
   104→    ) -> Result<RetrainingDecision, MonitorError> {
   105→        if window.len() < self.window_size {
   106→            return Ok(RetrainingDecision::NoAction);
   107→        }
   108→        let avg: f64 = window
   109→            .iter()
   110→            .rev()
   111→            .take(self.window_size)
   112→            .map(|s| s.value)
   113→            .sum::<f64>()
   114→            / self.window_size as f64;
   115→
   116→        debug!(
   117→            "[Strategy::StatisticalAverage] avg={:.4} threshold={:.4}",
   118→            avg, self.min_acceptable_score
   119→        );
   120→
   121→        if avg < self.min_acceptable_score {
   122→            Ok(RetrainingDecision::ShouldRetrain)
   123→        } else {
   124→            Ok(RetrainingDecision::NoAction)
   125→        }
   126→    }
   127→}
   128→
   129→/// Central coordinator that
   130→///   • accumulates metric samples in a ring buffer,
   131→///   • notifies observers,
   132→///   • delegates to strategies for retraining decisions.
   133→///
   134→#[derive(Clone)]
   135→pub struct ModelMonitor {
   136→    inner: Arc<Mutex<Inner>>,
   137→}
   138→
   139→struct Inner {
   140→    window: VecDeque<MetricSample>,
   141→    max_window: usize,
   142→    observers: Vec<Arc<dyn MetricObserver>>,
   143→    strategies: Vec<Arc<dyn RetrainingStrategy>>,
   144→    cooldown: Duration,
   145→    last_retrain_at: Option<Instant>,
   146→}
   147→
   148→impl ModelMonitor {
   149→    /// Create a new monitor.
   150→    ///
   151→    /// `max_window`  – maximum number of samples kept per metric  
   152→    /// `cooldown`    – minimum delay between two retraining triggers
   153→    pub fn new(max_window: usize, cooldown: Duration) -> Self {
   154→        assert!(max_window > 1, "max_window must be > 1");
   155→
   156→        Self {
   157→            inner: Arc::new(Mutex::new(Inner {
   158→                window: VecDeque::with_capacity(max_window),
   159→                max_window,
   160→                observers: Vec::new(),
   161→                strategies: Vec::new(),
   162→                cooldown,
   163→                last_retrain_at: None,
   164→            })),
   165→        }
   166→    }
   167→
   168→    /// Register a new observer.  Failures in an observer do not abort the
   169→    /// ingest flow; they are logged and swallowed.
   170→    pub fn register_observer<O>(&self, observer: O)
   171→    where
   172→        O: MetricObserver,
   173→    {
   174→        self.inner.lock().unwrap().observers.push(Arc::new(observer));
   175→    }
   176→
   177→    /// Register a new retraining strategy.  The first strategy voting for
   178→    /// `ShouldRetrain` short-circuits evaluation of further strategies.
   179→    pub fn register_strategy<S>(&self, strategy: S)
   180→    where
   181→        S: RetrainingStrategy,
   182→    {
   183→        self.inner.lock().unwrap().strategies.push(Arc::new(strategy));
   184→    }
   185→
   186→    /// Ingest a single metric sample into the monitor.
   187→    ///
   188→    /// Return `Ok(true)`  if a retraining event was emitted.  
   189→    /// Return `Ok(false)` if no action was taken.  
   190→    /// Return `Err(_)`    if a strategy returned an unrecoverable error.
   191→    pub fn ingest_metric(&self, sample: MetricSample) -> Result<bool, MonitorError> {
   192→        let mut inner = self.inner.lock().unwrap();
   193→
   194→        // 1) add sample to ring buffer
   195→        if inner.window.len() == inner.max_window {
   196→            inner.window.pop_front();
   197→        }
   198→        inner.window.push_back(sample.clone());
   199→
   200→        // 2) notify observers
   201→        for obs in &inner.observers {
   202→            if let Err(e) = obs.on_metric(&sample) {
   203→                error!("observer failed: {}", e);
   204→            }
   205→        }
   206→
   207→        // 3) consult each strategy
   208→        for strategy in &inner.strategies {
   209→            match strategy.evaluate(&sample.metric_name, &inner.window) {
   210→                Ok(RetrainingDecision::ShouldRetrain) => {
   211→                    let now = Instant::now();
   212→                    if inner
   213→                        .last_retrain_at
   214→                        .map_or(true, |t| now.duration_since(t) >= inner.cooldown)
   215→                    {
   216→                        inner.last_retrain_at = Some(now);
   217→                        info!(
   218→                            "Retraining triggered for metric '{}' (cooldown = {:?})",
   219→                            sample.metric_name, inner.cooldown
   220→                        );
   221→                        return Ok(true);
   222→                    } else {
   223→                        warn!("Retraining skipped due to cooldown.");
   224→                        return Ok(false);
   225→                    }
   226→                }
   227→                Ok(RetrainingDecision::NoAction) => {
   228→                    // continue with next strategy
   229→                }
   230→                Err(e) => return Err(e),
   231→            }
   232→        }
   233→
   234→        Ok(false)
   235→    }
   236→}
