    37→/// Initialize tracing + telemetry once for the whole test-suite.
    38→///
    39→/// The VisuTility Orchestrator uses `tracing` internally, therefore having a
    40→/// subscriber in place allows both library code and our test code to emit
    41→/// diagnostics without interfering with each other.
    42→///
    43→/// We lazily initialise the subscriber on the first invocation to prevent
    44→/// double-registration panics when multiple tests are run in parallel.
    45→fn init_tracing() {
    46→    static ONCE: std::sync::Once = std::sync::Once::new();
    47→    ONCE.call_once(|| {
    48→        telemetry::configure_subscriber(Level::INFO).expect("Failed to init telemetry");
    49→    });
    50→}
    51→
    52→/// A convenience macro that wraps an async expression in a [`tokio::time::timeout`] with a
    53→/// reasonable default, turning panics into proper `anyhow::Error`s.
    54→///
    55→/// This is particularly handy in flaky CI environments where a stalled future
    56→/// would otherwise hang the entire test run.
    57→macro_rules! within {
    58→    ($duration:expr, $expr:expr) => {
    59→        timeout($duration, $expr)
    60→            .await
    61→            .with_context(|| format!("timeout after {:?}", $duration))?
    62→    };
    63→}
