    69→#[tokio::test(flavor = "multi_thread", worker_threads = 4)]
    70→async fn pipeline_instantiation_for_rgb_camera() -> Result<()> {
    71→    init_tracing();
    72→
    73→    // ---------------------------------------------------------------------
    74→    // GIVEN: an RGB camera feed coming from a manufacturing line
    75→    // ---------------------------------------------------------------------
    76→    let camera_meta = CameraMeta::new("cam-rgb-01", "RGB", 30 /*fps*/);
