    17→use std::{
    18→    sync::{
    19→        atomic::{AtomicUsize, Ordering},
    20→        Arc,
    21→    },
    22→    time::Duration,
    23→};
    24→
    25→use anyhow::Result;
    26→use tokio::{sync::Mutex, time::timeout};
    27→
    28→use visutility_orchestrator::{
    29→    events::{EventBus, RetrainEvent},
    30→    factory::{DataPreprocessorFactory, SensorModality},
    31→    model::{MockModel, ModelId},
    32→    preprocessing::{FrameBatch, Preprocessor},
