    35→
    36→/// Helper that blocks until a condition is met or the timeout elapses.
    37→/// This is useful when testing asynchronous Observer-pattern events.
    38→async fn wait_until<F>(max_wait: Duration, condition: F) -> bool
    39→where
    40→    F: Fn() -> bool,
    41→{
    42→    timeout(max_wait, async {
    43→        loop {
    44→            if condition() {
    45→                return true;
    46→            }
    47→            tokio::time::sleep(Duration::from_millis(5)).await;
    48→        }
    49→    })
    50→    .await
    51→    .unwrap_or(false)
    52→}
