    54→#[tokio::test]
    55→async fn test_preprocessor_factory_resolves_expected_concrete_types() -> Result<()> {
    56→    // RGB
    57→    let rgb: Box<dyn Preprocessor> =
    58→        DataPreprocessorFactory::for_modality(SensorModality::Rgb)?;
    59→    assert_eq!(rgb.name(), "RgbPreprocessor");
    60→
    61→    // Thermal
    62→    let thermal: Box<dyn Preprocessor> =
    63→        DataPreprocessorFactory::for_modality(SensorModality::Thermal)?;
    64→    assert_eq!(thermal.name(), "ThermalPreprocessor");
    65→
    66→    // Depth
    67→    let depth: Box<dyn Preprocessor> =
    68→        DataPreprocessorFactory::for_modality(SensorModality::Depth)?;
    69→    assert_eq!(depth.name(), "DepthPreprocessor");
    70→
    71→    // Validate that each concrete type can process a dummy batch.
    72→    let dummy_batch = FrameBatch::dummy(4);
    73→    for proc in [rgb, thermal, depth] {
    74→        let output = proc.preprocess(dummy_batch.clone()).await?;
    75→        assert_eq!(output.len(), dummy_batch.len());
    76→        assert!(
    77→            output
    78→                .iter()
    79→                .all(|frame| frame.is_preprocessed()),
    80→            "every frame should be flagged as pre-processed"
    81→        );
    82→    }
    83→
    84→    Ok(())
    85→}
