    87→#[tokio::test]
    88→async fn test_model_registry_versioning_and_retrieval_roundtrip() -> Result<()> {
    89→    // In a multi-tenant environment, each (tenant, model_name) pair gets its own sequence.
    90→    let tenant_id = "acme-factory-42";
    91→    let model_name = "conveyor-object-detector";
    92→
    93→    let registry = ModelRegistry::new_in_memory();
    94→
    95→    // Register 3 versions sequentially.
    96→    for idx in 0..3 {
    97→        let mock_model = MockModel::new(ModelId::new(format!("mock/v{}", idx)));
    98→        let meta = ModelMetadata {
    99→            name: model_name.into(),
   100→            tenant: tenant_id.into(),
   101→            description: Some(format!("unit-test version {}", idx)),
   102→            artifact_path: format!("/tmp/mock_model_v{}.onnx", idx).into(),
   103→            additional: None,
   104→        };
   105→        registry.register(mock_model, meta.clone()).await?;
   106→    }
   107→
   108→    // Latest should be version 3.
   109→    let latest_entry = registry.latest(tenant_id, model_name).await?;
   110→    assert_eq!(latest_entry.version, ModelVersion(3));
   111→
   112→    // Query by explicit version.
   113→    let v2_entry = registry
   114→        .by_version(tenant_id, model_name, ModelVersion(2))
   115→        .await?;
   116→    assert_eq!(v2_entry.version, ModelVersion(2));
   117→
   118→    // Attempting to fetch a non-existent version should error.
   119→    let err = registry
   120→        .by_version(tenant_id, model_name, ModelVersion(99))
   121→        .await
   122→        .expect_err("version 99 should not exist");
   123→    assert!(
   124→        err.to_string().contains("not found"),
   125→        "error message should mention model not found"
   126→    );
   127→
   128→    Ok(())
   129→}
