   131→#[tokio::test]
   132→async fn test_retrain_event_bus_notifies_subscribers() -> Result<()> {
   133→    // Shared assertion state.
   134→    let counter = Arc::new(AtomicUsize::new(0));
   135→
   136→    let bus = EventBus::default();
   137→
   138→    // Create three independent subscribers.
   139→    for _ in 0..3 {
   140→        let c = counter.clone();
   141→        let mut rx = bus.subscribe::<RetrainEvent>();
   142→        tokio::spawn(async move {
   143→            while let Ok(evt) = rx.recv().await {
   144→                // Simple integrity checks.
   145→                assert!(
   146→                    !evt.tenant_id.is_empty() && !evt.model_name.is_empty(),
   147→                    "event should carry identifying payload"
   148→                );
   149→                c.fetch_add(1, Ordering::SeqCst);
   150→            }
   151→        });
   152→    }
   153→
   154→    // Emit a single retrain event.
   155→    let evt = RetrainEvent {
   156→        tenant_id: "acme-factory-42".into(),
   157→        model_name: "conveyor-object-detector".into(),
   158→        triggered_at: chrono::Utc::now(),
   159→        reason: Some("integration-test".into()),
   160→    };
   161→    bus.publish(evt).await?;
   162→
   163→    // Wait until all listeners increment the counter or time out.
   164→    let all_received = wait_until(Duration::from_secs(2), || counter.load(Ordering::SeqCst) == 3)
   165→        .await;
   166→    assert!(
   167→        all_received,
   168→        "all subscribers should have processed the event exactly once"
   169→    );
   170→
   171→    Ok(())
   172→}
